(() => {
  const svg = d3.select('svg');
  const chart = svg.select('g.chart-skeleton');
  const ann = svg.select('g.annotation-layer.operation-next-annotation-layer');

  // Remove any prior instance for idempotency
  ann.selectAll('g.overall-average').remove();

  // Read CPI values from existing points
  const pts = chart.selectAll('g.point-marks circle').nodes();
  const values = pts
    .map(n => +n.getAttribute('data-y-value'))
    .filter(v => Number.isFinite(v));

  if (!values.length) return;

  const mean = d3.mean(values);

  // Use existing y-axis tick positions to map value -> y (linear)
  const yTicks = chart.selectAll('g.y-axis g.tick').nodes().map(t => {
    const tr = t.getAttribute('transform');
    const m = /translate\(0,\s*([\d.\-]+)\)/.exec(tr);
    const y = m ? +m[1] : NaN;
    const txt = t.querySelector('text');
    const v = txt ? +txt.textContent : NaN;
    return { v, y };
  }).filter(d => Number.isFinite(d.v) && Number.isFinite(d.y));

  // Fallback if ticks missing
  if (yTicks.length < 2) return;

  // Determine linear mapping y = a*v + b
  const tMin = d3.min(yTicks, d => d.v);
  const tMax = d3.max(yTicks, d => d.v);
  const yAtMin = yTicks.find(d => d.v === tMin).y;
  const yAtMax = yTicks.find(d => d.v === tMax).y;
  const a = (yAtMax - yAtMin) / (tMax - tMin);
  const b = yAtMin - a * tMin;
  const yMean = a * mean + b;

  const plotW = +svg.attr('data-plot-w') || 520;

  const g = ann.append('g')
    .attr('class', 'overall-average')
    .attr('clip-path', 'url(#plot-clip-1)');

  g.append('line')
    .attr('x1', 0)
    .attr('x2', plotW)
    .attr('y1', yMean)
    .attr('y2', yMean)
    .attr('stroke', '#111827')
    .attr('stroke-width', 2)
    .attr('stroke-dasharray', '6,6')
    .attr('opacity', 0.85);

  // Label near right edge, kept inside plot
  const labelText = 'Overall average';
  const labelW = 112;
  const labelH = 20;
  const padRight = 4;
  const labelX = plotW - labelW - padRight;
  const labelY = Math.max(-6, Math.min(300 - labelH - 2, yMean - labelH / 2));

  g.append('rect')
    .attr('x', labelX)
    .attr('y', labelY)
    .attr('width', labelW)
    .attr('height', labelH)
    .attr('rx', 4)
    .attr('ry', 4)
    .attr('fill', '#ffffff')
    .attr('opacity', 0.9)
    .attr('stroke', '#111827')
    .attr('stroke-width', 1);

  g.append('text')
    .attr('x', labelX + labelW / 2)
    .attr('y', labelY + labelH / 2 + 4)
    .attr('text-anchor', 'middle')
    .attr('font-size', 13)
    .attr('font-weight', 700)
    .attr('fill', '#111827')
    .text(labelText);
})();

(() => {
  const svg = d3.select('svg');
  const chart = svg.select('g.chart-skeleton');
  const ann = svg.select('g.annotation-layer.operation-next-annotation-layer');

  // Idempotency
  ann.selectAll('g.year-averages').remove();

  const pts = chart.selectAll('g.point-marks circle').nodes().map(n => {
    const label = n.getAttribute('data-x-value') || n.getAttribute('data-id') || '';
    const v = +n.getAttribute('data-y-value');
    const cx = +n.getAttribute('cx');
    return { label, v, cx };
  }).filter(d => Number.isFinite(d.v) && Number.isFinite(d.cx));

  if (!pts.length) return;

  // Parse year from labels like "May '20" / "Jan '21"
  const parseYear = (label) => {
    const m = /'\s*(\d{2})\b/.exec(label);
    if (!m) return null;
    const yy = +m[1];
    return 2000 + yy;
  };

  const byYear = d3.group(pts, d => parseYear(d.label));

  // Build y mapping from y-axis ticks (linear)
  const yTicks = chart.selectAll('g.y-axis g.tick').nodes().map(t => {
    const tr = t.getAttribute('transform');
    const m = /translate\(0,\s*([\d.\-]+)\)/.exec(tr);
    const y = m ? +m[1] : NaN;
    const txt = t.querySelector('text');
    const v = txt ? +txt.textContent : NaN;
    return { v, y };
  }).filter(d => Number.isFinite(d.v) && Number.isFinite(d.y));
  if (yTicks.length < 2) return;

  const tMin = d3.min(yTicks, d => d.v);
  const tMax = d3.max(yTicks, d => d.v);
  const yAtMin = yTicks.find(d => d.v === tMin).y;
  const yAtMax = yTicks.find(d => d.v === tMax).y;
  const a = (yAtMax - yAtMin) / (tMax - tMin);
  const b = yAtMin - a * tMin;
  const yScale = (v) => a * v + b;

  const g = ann.append('g')
    .attr('class', 'year-averages')
    .attr('clip-path', 'url(#plot-clip-1)');

  const plotW = +svg.attr('data-plot-w') || 520;

  const yearSpecs = [
    { year: 2020, cls: 'avg-2020', stroke: '#1d4ed8', bandX0: 0, bandX1: 320 },
    { year: 2021, cls: 'avg-2021', stroke: '#047857', bandX0: 320, bandX1: plotW }
  ];

  yearSpecs.forEach(spec => {
    const arr = byYear.get(spec.year);
    if (!arr || !arr.length) return;

    const mean = d3.mean(arr, d => d.v);
    const y = yScale(mean);

    // Segment inside band with padding
