      .attr('x1', x1)
      .attr('x2', x2)
      .attr('y1', y)
      .attr('y2', y)
      .attr('stroke', spec.stroke)
      .attr('stroke-width', 4)
      .attr('stroke-linecap', 'round')
      .attr('opacity', 0.95);

    // Label placed slightly below the segment to avoid overlap with the dashed overall-average line
    const labelText = `${spec.year} avg`;
    const labelW = 72;
    const labelH = 18;
    const labelX = (spec.bandX0 + spec.bandX1) / 2 - labelW / 2;
    const labelY = Math.max(-6, Math.min(300 - labelH - 2, y + 8));

    g.append('rect')
      .attr('class', `avg-label-bg ${spec.cls}`)
      .attr('x', labelX)
      .attr('y', labelY)
      .attr('width', labelW)
      .attr('height', labelH)
